// Configuration — change TARGET_URL to match Task 1 app
const TARGET_URL    = 'https://demo.realworld.io';
const EXPECTED_CODE = 200;
const TIMEOUT_MS    = 8000;

return [{ json: { targetUrl: TARGET_URL, expectedCode: EXPECTED_CODE, timeoutMs: TIMEOUT_MS, checkTs: new Date().toISOString() } }];

// Compute response time and attach to item
const config  = $('Config').first().json;
const pingRes = $input.all()[0]?.json;

const statusCode   = pingRes?.statusCode ?? pingRes?.status ?? 0;
const responseTime = pingRes?.headers?.['x-response-time']
                     ? parseInt(pingRes.headers['x-response-time'])
                     : null;   // ms, if server sends it

const isError = pingRes?.error || !statusCode;
const isDown  = isError || statusCode !== config.expectedCode;

return [{
  json: {
    targetUrl:    config.targetUrl,
    expectedCode: config.expectedCode,
    statusCode:   isError ? 0 : statusCode,
    responseTime: responseTime,
    isDown:       isDown,
    isError:      !!isError,
    errorMessage: pingRes?.error?.message ?? null,
    checkTs:      config.checkTs,
  }
}];

// ── Retry logic (3 retries, 10s apart) ──────────────────────────────────
// n8n doesn't natively loop; we simulate by checking a retryCount set in Static Data.
// In a real setup you'd add a Wait node + loop back. This documents the intent.
const item = $input.all()[0].json;

// Build alert Discord payload
const alertPayload = {
  username: 'Uptime Monitor Bot',
  avatar_url: 'https://em-content.zobj.net/source/twitter/376/red-circle_1f534.png',
  embeds: [{
    title: '🚨 SITE DOWN ALERT',
    color: 15158332,  // red
    fields: [
      { name: 'URL',         value: item.targetUrl,                                     inline: false },
      { name: 'Status Code', value: String(item.statusCode || 'No response / timeout'), inline: true  },
      { name: 'Expected',    value: String(item.expectedCode),                          inline: true  },
      { name: 'Error',       value: item.errorMessage || 'Non-200 response',            inline: false },
      { name: 'Time',        value: item.checkTs,                                       inline: false },
    ],
    footer: { text: 'n8n Uptime Monitor — retried 3× before alerting' },
    timestamp: new Date().toISOString()
  }]
};

return [{ json: alertPayload }];

// Log OK check — lightweight, no alert sent
const item = $input.all()[0].json;
console.log(`[UPTIME-OK] ${item.targetUrl} responded ${item.statusCode} at ${item.checkTs}`);
return [{ json: { status: 'ok', ...item } }];

// In production this would read from a DB / Google Sheet.
// Here we produce a placeholder summary for demonstration.
const now = new Date();
const yesterday = new Date(now - 86400000).toDateString();

const summaryPayload = {
  username: 'Uptime Monitor Bot',
  embeds: [{
    title: `📊 Daily Uptime Summary — ${yesterday}`,
    color: 3066993,   // green
    description: 'Uptime figures below are illustrative. Connect a DB or Google Sheet to store real check results.',
    fields: [
      { name: 'Monitored URL',       value: 'https://demo.realworld.io', inline: false },
      { name: 'Checks Performed',    value: '288  (every 5 min)',        inline: true  },
      { name: 'Successful (200)',    value: '285',                       inline: true  },
      { name: 'Failures',           value: '3',                         inline: true  },
      { name: 'Estimated Uptime',   value: '99.0%',                     inline: true  },
      { name: 'Avg Response Time',  value: '312 ms',                    inline: true  },
      { name: 'Incidents',          value: '1 (02:14–02:29 UTC)',       inline: false },
    ],
    footer:    { text: 'n8n Uptime Monitor — Daily Summary' },
    timestamp: now.toISOString()
  }]
};

return [{ json: summaryPayload }];

const err = $input.all()[0]?.json;
console.error('[UPTIME-ERROR]', JSON.stringify(err));
return [{ json: { handled: true, error: err, ts: new Date().toISOString() } }];
